script:
frappe.ui.form.on('FSM Inventory', {

    scan_input: function(frm) {
        handle_barcode_scan(frm);
    },

    group: (frm) => fetch_inventory_items(frm),
    warehouse: (frm) => fetch_inventory_items(frm),
    buying_price_list: (frm) => fetch_inventory_items(frm),
    selling_price_list: (frm) => fetch_inventory_items(frm)
});


// ===============================
// CHILD TABLE EVENTS
// ===============================
frappe.ui.form.on('FSM Inventory Item', {

    counted_qty: function(frm, cdt, cdn) {
        on_row_change(frm, cdt, cdn);
    },

    qty_offset: function(frm, cdt, cdn) {
        on_row_change(frm, cdt, cdn);
    },

    buying_price: function(frm, cdt, cdn) {
        on_row_change(frm, cdt, cdn);
    }

});


// ===============================
// CENTRALIZED ROW UPDATE LOGIC
// ===============================
function on_row_change(frm, cdt, cdn) {
    update_row_values(frm, cdt, cdn);
    calculate_totals(frm);
}


// ===============================
// UPDATE SINGLE ROW VALUES
// ===============================
function update_row_values(frm, cdt, cdn) {

    let row = locals[cdt][cdn];

    let qty_offset = Math.abs(
        (row.counted_qty || 0) - (row.expected_qty || 0)
    );

    let value_offset = qty_offset * (row.buying_price || 0);

    frappe.model.set_value(cdt, cdn, {
        qty_offset: qty_offset,
        value_offset: value_offset
    });
}


// ===============================
// BARCODE SCAN LOGIC
// ===============================
function handle_barcode_scan(frm) {

    const val = (frm.doc.scan_input || "").trim();
    if (!val) return;

    const row = (frm.doc.fsm_inventory_item || []).find(d =>
        (d.barcode && d.barcode.trim() === val) ||
        (d.item_code && d.item_code.trim().toLowerCase() === val.toLowerCase())
    );

    if (row) {

        frappe.model.set_value(row.doctype, row.name, {
            counted_qty: (row.counted_qty || 0) + 1,
            scanned: 1
        }).then(() => {

            update_row_values(frm, row.doctype, row.name);
            calculate_totals(frm);

        });

        frm.set_value('scan_input', '');

        frappe.show_alert({
            message: __("Counted: {0}", [row.item_code]),
            indicator: 'green'
        }, 1);
    }
}


// ===============================
// FETCH ITEMS FROM BACKEND
// ===============================
function fetch_inventory_items(frm) {

    frm.clear_table('fsm_inventory_item');

    if (!frm.doc.warehouse) {
        frm.refresh_field('fsm_inventory_item');
        return;
    }

    frappe.call({
        method: "inventory_vue_app.api.get_items_with_details",
        args: {
            item_group: frm.doc.group || "",
            warehouse: frm.doc.warehouse,
            buying_price_list: frm.doc.buying_price_list,
            selling_price_list: frm.doc.selling_price_list
        },
        freeze: true,

        callback: function(r) {

            if (r.message) {

                r.message.forEach(item => {

                    let child = frm.add_child('fsm_inventory_item');

                    child.item_code     = item.item_code;
                    child.item_name     = item.item_name;
                    child.expected_qty  = item.qty;
                    child.counted_qty   = 0;

                    child.buying_price  = item.buying_rate;
                    child.selling_price = item.selling_rate;

                    child.barcode       = item.barcode;

                    // initial calculation
                    child.qty_offset    = item.qty;
                    child.value_offset  = (item.qty || 0) * (item.buying_rate || 0);
                });

                frm.refresh_field('fsm_inventory_item');
            }

            calculate_totals(frm);
        }
    });
}


// ===============================
// TOTALS CALCULATION
// ===============================
function calculate_totals(frm) {

    let total_counted_qty  = 0;
    let total_expected_qty = 0;
    let total_qty_offset   = 0;

    (frm.doc.fsm_inventory_item || []).forEach(row => {

        total_counted_qty  += (row.counted_qty  || 0);
        total_expected_qty += (row.expected_qty || 0);
        total_qty_offset   += (row.qty_offset   || 0);
    });

    frm.set_value('total_counted_qty', total_counted_qty);
    frm.set_value('total_expected_qty', total_expected_qty);
    frm.set_value('total_qty_offset', total_qty_offset);
}
